import React, { useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { utils, read } from 'xlsx';

// Mapeo de columna en el Excel exportado → (action, pointValue)
// La tabla tiene: Jugadores | Recepción(6) | Ataque(6) | Contraataque(6) | Bloqueo(4) | Saque(5) | Error(1)
const COL_MAP = [
    null, // 0: nombre
    ['recepcion',       'recepcion_++'],
    ['recepcion',       'recepcion_+'],
    ['recepcion',       'recepcion_-'],
    ['recepcion',       'recepcion_saque_ganado'],
    ['recepcion',       'recepcion_ace'],
    null, // Total recepción
    ['ataque',          'ataque_++'],
    ['ataque',          'ataque_+'],
    ['ataque',          'ataque_-'],
    ['ataque',          'ataque_error_de_bloqueo'],
    ['ataque',          'ataque_error'],
    null, // Total ataque
    ['contra-ataque',   'contraataque_++'],
    ['contra-ataque',   'contraataque_+'],
    ['contra-ataque',   'contraataque_-'],
    ['contra-ataque',   'contraataque_error_de_bloqueo'],
    ['contra-ataque',   'contraataque_error'],
    null, // Total contraataque
    ['bloqueo',         'bloqueo_+'],
    ['bloqueo',         'bloqueo_def'],
    ['bloqueo',         'bloqueo_-'],
    null, // Total bloqueo
    ['saque',           'saque_ace'],
    ['saque',           'saque_+'],
    ['saque',           'saque_-'],
    ['saque',           'saque_error'],
    null, // Total saque
    ['error_por_regla', 'error_por_regla_error'],
];

function parseExportSheet(sheet, setNumber) {
    const rows = utils.sheet_to_json(sheet, { header: 1, defval: '' });
    // rows[0] = header categorías, rows[1] = sub-header, rows[2+] = datos
    const dataRows = rows.slice(2);
    const stats = [];

    for (const row of dataRows) {
        const playerName = (row[0] || '').toString().trim();
        if (!playerName) continue;

        for (let col = 1; col < COL_MAP.length; col++) {
            const mapping = COL_MAP[col];
            if (!mapping) continue; // columna de total
            const count = parseInt(row[col], 10);
            if (isNaN(count) || count <= 0) continue;

            const [action, pointValue] = mapping;
            for (let i = 0; i < count; i++) {
                stats.push({ playerName, action, pointValue, setNumber });
            }
        }
    }
    return stats;
}

function parseSimpleSheet(sheet) {
    const raw = utils.sheet_to_json(sheet, { defval: '' });
    const stats = [];

    for (const row of raw) {
        const playerName = (row.playerName || row.PlayerName || row.Jugador || '').toString().trim();
        const action     = (row.action || row.Action || row.Accion || row.Acción || row.Fundamento || '').toString().trim();
        const pointValue = (row.pointValue || row.PointValue || row.Valor || row.Resultado || '').toString().trim();
        const setNumber  = parseInt(row.setNumber || row.SetNumber || row.Set || 1, 10);

        if (!playerName || !action || !pointValue) continue;
        stats.push({ playerName, action, pointValue, setNumber: isNaN(setNumber) ? 1 : setNumber });
    }
    return stats;
}

function parseGameName(wb) {
    // Hoja "Resultado" del export: ["", "Mariano Moreno", "Rival"]
    const resultSheet = wb.Sheets['Resultado'];
    if (resultSheet) {
        const rows = utils.sheet_to_json(resultSheet, { header: 1, defval: '' });
        if (rows.length > 0 && rows[0].length >= 3) {
            const name = (rows[0][2] || '').toString().trim();
            if (name) return name;
        }
    }
    // Hoja "Partido" con columna "rival" o "gameName"
    const partidoSheet = wb.Sheets['Partido'];
    if (partidoSheet) {
        const rows = utils.sheet_to_json(partidoSheet, { header: 1, defval: '' });
        const rivalRow = rows.find(r => (r[0] || '').toString().toLowerCase().includes('rival'));
        if (rivalRow && rivalRow[1]) return rivalRow[1].toString().trim();

        const json = utils.sheet_to_json(partidoSheet, { defval: '' });
        if (json.length) {
            return json[0].gameName || json[0].Rival || json[0].rival || '';
        }
    }
    return '';
}

function ImportExcel({ onImportStats }) {
    const fileRef = useRef(null);
    const navigate = useNavigate();
    const [error, setError] = useState(null);
    const [importing, setImporting] = useState(false);

    const handleFile = async (e) => {
        const file = e.target.files[0];
        if (!file) return;

        setError(null);
        setImporting(true);

        try {
            const buf = await file.arrayBuffer();
            const wb = read(buf, { type: 'array' });

            let stats = [];
            let gameName = parseGameName(wb);

            // Prioridad 1: hojas "Set 1", "Set 2", etc. (formato export)
            const setSheets = wb.SheetNames
                .filter(n => /^Set\s+\d+$/i.test(n))
                .sort((a, b) => {
                    const na = parseInt(a.match(/\d+/)[0], 10);
                    const nb = parseInt(b.match(/\d+/)[0], 10);
                    return na - nb;
                });

            if (setSheets.length > 0) {
                for (const sheetName of setSheets) {
                    const setNum = parseInt(sheetName.match(/\d+/)[0], 10);
                    const sheetStats = parseExportSheet(wb.Sheets[sheetName], setNum);
                    stats.push(...sheetStats);
                }
            } else if (wb.Sheets['Estadisticas totales']) {
                // Prioridad 2: hoja "Estadisticas totales" (formato export, sin set)
                stats = parseExportSheet(wb.Sheets['Estadisticas totales'], 0);
            } else if (wb.Sheets['Estadisticas']) {
                // Prioridad 3: hoja "Estadisticas" (formato simple)
                stats = parseSimpleSheet(wb.Sheets['Estadisticas']);
            } else {
                throw new Error(
                    'No encontré una hoja con datos. El Excel debe tener:\n' +
                    '• "Set 1", "Set 2"… (exportado desde la app), o\n' +
                    '• Hoja "Estadisticas totales" (exportado), o\n' +
                    '• Hoja "Estadisticas" con columnas playerName, action, pointValue, setNumber'
                );
            }

            if (!stats.length) {
                throw new Error('No se encontraron estadísticas válidas en el archivo.');
            }

            if (!gameName) gameName = 'Importado';

            // Limpiar y cargar
            localStorage.removeItem('stats');
            localStorage.removeItem('localScore');
            localStorage.removeItem('visitScore');
            localStorage.removeItem('results');
            localStorage.setItem('stats', JSON.stringify(stats));
            localStorage.setItem('gameName', gameName);

            onImportStats(stats, gameName);
            setImporting(false);
            navigate('/resultados');
        } catch (err) {
            setError(err.message);
            setImporting(false);
        }
    };

    return (
        <div className="import-page">
            <h2 className="import-title">Importar estadísticas</h2>

            <div className="import-card">
                <p className="import-desc">
                    Subí un archivo Excel (.xlsx). Acepta:
                </p>

                <ul className="import-list">
                    <li><strong>Exportado desde la app</strong> — con hojas "Set 1", "Set 2"… y "Resultado"</li>
                    <li><strong>Formato simple</strong> — hoja "Estadisticas" con columnas: <code>playerName</code>, <code>action</code>, <code>pointValue</code>, <code>setNumber</code></li>
                </ul>

                <input
                    ref={fileRef}
                    type="file"
                    accept=".xlsx,.xls"
                    onChange={handleFile}
                    style={{ display: 'none' }}
                />

                <button
                    className="import-btn"
                    disabled={importing}
                    onClick={() => fileRef.current?.click()}
                >
                    {importing ? (
                        <>Procesando…</>
                    ) : (
                        <><i className="bi bi-upload"></i> Seleccionar archivo</>
                    )}
                </button>

                {error && (
                    <div className="import-error">
                        <i className="bi bi-exclamation-triangle-fill"></i> {error}
                    </div>
                )}
            </div>
        </div>
    );
}

export default ImportExcel;
